# "clean" = a fact fully closed: balanced parens/brackets in the reconstructed one-line, no empty "(  )"
def clean(s):
    if '(  )' in s or ',,' in s: return False
    if s.count('(')!=s.count(')'): return False
    if s.count('[')!=s.count(']'): return False
    return True

