                        if (a.startswith('--[') or a=='-->') and c.startswith('[') and (nxt=='' or hdr.match(nxt)):
                            actual=True; oneline=p+' '+a+' '+c; i=j+3
                        else:
                            i=j+1; continue
                    else:
                        i=j+1; continue
                if not clean(oneline):
                    continue
                total+=1
                ew=esc_len(oneline); pred=ew>67
                if pred!=actual:
                    mism+=1
                    if len(ex)<20: ex.append((ew,actual,oneline))
            else: i+=1
    print(f"[{label}] clean bodies judged={total}  mispredicted={mism}  accuracy={100*(total-mism)/total:.2f}%")
    for ew,a,s in ex: print(f"   esc={ew} actual_wrap={a} pred={ew>67}: {s!r}")

